/* AutoTrack+ minimal controller (debug-friendly)
 * Goals: prove script is loaded, wire clicks robustly, populate right panel.
 * No dependencies. Keep selectors tolerant so it works with your current HTML.
 */

(() => {
  console.log("AT+ app.min.js loaded");

  const $ = (s, c = document) => c.querySelector(s);
  const $$ = (s, c = document) => [...c.querySelectorAll(s)];

  // Elements we expect to exist
  const LIST   = $("#vehicle-list") || document;   // fall back to page if no id
  const PANEL  = $("#vehicle-panel") || createPanel();
  const SEARCH = $("#search");

  // Helper: create a panel if the page didn’t have one
  function createPanel() {
    const p = document.createElement("section");
    p.id = "vehicle-panel";
    p.className = "panel";
    p.innerHTML = `<div class="empty"><p>Select a vehicle from the list.</p></div>`;
    // Try to place it after the list container if possible
    (LIST.closest(".split") || document.body).appendChild(p);
    return p;
  }

  // Render right panel using whatever text exists in the left card
  function renderPanelFromCard(card) {
    const title = (card.querySelector("strong") || card.querySelector("header") || card).textContent.trim();
    const small = (card.querySelector("small") || {}).textContent || "";
    const plate = (title.match(/\(([^)]+)\)/) || [,""])[1];

    PANEL.innerHTML = `
      <div class="vehicle-detail">
        <header class="vd-head">
          <h2>${escapeHtml(title)}</h2>
          ${plate ? `<span class="badge">${escapeHtml(plate)}</span>` : ""}
        </header>
        <div class="grid-3 gap">
          <div class="tile"><div class="label">Next Service</div><div class="value">${readField(card,["[data-next]","time",".next",".due","small"])}</div></div>
          <div class="tile"><div class="label">Insurance Expiry</div><div class="value">${readField(card,["[data-ins]",".ins","small"])}</div></div>
          <div class="tile"><div class="label">Mileage</div><div class="value">${readField(card,["[data-mileage]",".miles","small"])}</div></div>
        </div>
        <div class="spacer"></div>
        <div class="row">
          <input class="input flex" id="repair-input" placeholder="e.g., Brake pads">
          <select class="input" id="repair-status">
            <option value="due">Due Soon</option>
            <option value="expired">Expired</option>
            <option value="ok">Completed</option>
          </select>
          <button class="btn" id="btn-add-repair">Add</button>
        </div>
        <ul class="repairs" id="repairs-list" aria-live="polite"><li class="muted">No repairs yet.</li></ul>
      </div>`;
  }

  function readField(card, selectors) {
    for (const sel of selectors) {
      const el = card.querySelector(sel);
      if (el && el.textContent.trim()) return escapeHtml(el.textContent.trim());
      if (el && el.value) return escapeHtml(el.value);
    }
    return "—";
  }

  function escapeHtml(s) {
    return String(s).replace(/[&<>"']/g, m => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]));
  }

  // --- Event delegation for the whole page ---
  document.addEventListener("click", (e) => {
    const card = e.target.closest(".vehicle-card, .card, article, li");
    const inList = card && (LIST.contains(card) || card.closest("#vehicle-list"));

    // Remove button (match by data-role, class, or label text)
    const removeBtn = e.target.closest('[data-role="remove"], .btn-remove, button, a');
    if (removeBtn && inList && btnLabel(removeBtn) === "remove") {
      e.preventDefault();
      if (confirm("Remove this vehicle?")) {
        card.remove();
        if (PANEL) PANEL.innerHTML = `<div class="empty"><p>Select a vehicle from the list.</p></div>`;
      }
      return;
    }

    // Details button → demo dialog (proves handler works)
    const detailsBtn = e.target.closest('[data-role="details"], .btn-details, button, a');
    if (detailsBtn && inList && btnLabel(detailsBtn) === "details") {
      e.preventDefault();
      alert("Details button clicked (wire your details page here).");
      return;
    }

    // Select a card to show details
    if (card && inList && !e.target.closest("footer")) {
      // visual active state
      $$(".active", LIST).forEach(x => x.classList.remove("active"));
      card.classList.add("active");
      renderPanelFromCard(card);
      return;
    }

    // Pills filter
    const pill = e.target.closest(".pill");
    if (pill && pill.closest("#filter-pills")) {
      e.preventDefault();
      $("#filter-pills .pill.active")?.classList.remove("active");
      pill.classList.add("active");
      filterList(pill.dataset.filter || "all", (SEARCH && SEARCH.value.trim().toLowerCase()) || "");
    }
  });

  // Search box
  SEARCH && SEARCH.addEventListener("input", () => {
    const f = ($("#filter-pills .pill.active") || {}).dataset?.filter || "all";
    filterList(f, SEARCH.value.trim().toLowerCase());
  });

  function btnLabel(btn) {
    return (btn.dataset.role || btn.textContent || "").trim().toLowerCase();
  }

  function filterList(filter, q) {
    // Try to filter only the left cards inside #vehicle-list, otherwise any cards
    const scope = $("#vehicle-list") || document;
    const items = $$(".vehicle-card, .card, article, li", scope);
    items.forEach(card => {
      const label = (card.textContent || "").toLowerCase();
      const state = card.dataset.state || // if present
                    (card.textContent.toLowerCase().includes("due soon") ? "due" :
                     card.textContent.toLowerCase().includes("expired")  ? "expired" : "ok");
      const stateMatch = (filter === "all") || (state === filter);
      const searchMatch = !q || label.includes(q);
      card.style.display = (stateMatch && searchMatch) ? "" : "none";
    });
  }

  // Give instant visual feedback that the script is alive
  setTimeout(() => {
    const host = document.createElement("div");
    host.id = "toast-host";
    Object.assign(host.style, {position:"fixed",right:"16px",bottom:"16px",zIndex:9999});
    document.body.appendChild(host);
    const t = document.createElement("div");
    t.textContent = "UI wired ✅";
    Object.assign(t.style, {background:"#111827",color:"#fff",padding:"8px 10px",borderRadius:"10px",opacity:"0.95"});
    host.appendChild(t);
    setTimeout(()=>host.remove(), 2000);
  }, 300);
})();
